head.script:
/**
 * 화 면 명 : 자산비용조정금액등록
 * 메뉴경로 : 회계/관리회계/실적관리/실적집계/자산비용관리/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/rsltsaggr/co_403_01_02b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-12-03
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항
 *    1. login정보 확인 필요 
 *     ☞  $c.data.getMemInfo() 처리
 *    2. [해결]<%@ page import="dbl.ac.am.constants.ACConstants" %> 상수가져오는건 공통에서 글로벌 상수로 변경할 듯. 
 *    3. 상수값 가져오는거 어떻게 할지? DGlobalValue.java 이런거 있을때마다 개발자가 DGlobalValue.js로 변경해서 올려야 하나?
 *    4. 엑셀다운로드 시 Number타입 excelFormat, excelCellType 옵션 추가 작업
 * 테스트데이터 :
 *    1. 회사코드[000], 실적, 마감년월[2026/03], 버전[002], 부서[00009:재경]
 * 수정이력 :
 *    - 2025-12-03      배기원    최초작성
 */
//hidden 값
scwin.txtCoClsCd = "";

scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;

//상수값(임시)
scwin.DGlobalValue = { "ALL": -1, "TRUE": 1, "FALSE": 0 };
scwin.closeYm  = "";
scwin.first = 0;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                      //소속자회사
    scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];             //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];//사용자소속구분코드
    scwin.isSubCompany = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.first = 0;
};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_master.setNoResultMessageVisible(false);
    ds_master.removeAll();
    totalRows.setValue("0");
    $c.gus.cfDisableObjects([btn_save]);
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.setInit();
    scwin.f_HeaderCreate();
    scwin.f_SetSrchDefault();
    $c.gus.cfDisableObjects([btn_save]);
    scwin.f_setCompanyInfo();
    dma_search.reform();
};

/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ica_srchCloseYm, rd_planRsltsClsCd, lc_version, ed_coCd, ed_coNm]);
    scwin.f_SetSrchDefault();
};

/**
 * 조회 기본값 설정
 */
scwin.f_SetSrchDefault = function() {
    rd_planRsltsClsCd.setValue("2");
    ed_srchAcctDeptCd.setValue("");
    ed_srchAcctDeptNm.setValue("");
    scwin.closeYm = $c.date.getServerDateTime().substring(0,6);
    ica_srchCloseYm.setValue(scwin.closeYm);
    scwin.f_GetVersion();
    ica_srchCloseYm.focus();
};


/**
 * 조회 데이터셋 헤더 생성
 * TOBE 사용안함
 */
scwin.f_HeaderCreate = function() {
    // var GAUCE_DATASET_HEADER = "closeYm:STRING"
    //     + ",ver:STRING"
    //     + ",acctDeptCd:STRING"
    //     + ",acctDeptNm:STRING"
    //     + ",planRsltsClsCd"
    //     + ",coCd";
    // ds_search.SetDataHeader(GAUCE_DATASET_HEADER);
    // ds_search.insertRow();
};


/**
* 조회버튼
*/
scwin.f_Retrieve = async function() {
    if (ds_master.getRowCount() > 0 && ds_master.getModifiedIndex().length > 0) {
        if (!await $c.win.confirm(MSG_CM_CRM_005)) {
            return;
        }
    }

    let ret = await $c.gus.cfValidate([ed_coCd, ica_srchCloseYm, lc_version, ed_srchAcctDeptCd]);
    if (!ret) {
        return false;
    }
    if(ica_srchCloseYm.getValue().length != 6){
        await $c.win.alert("마감년월은(는) 6자리수만큼 입력하십시오.");
        ica_srchCloseYm.focus();
        return;
    }
    ret = await $c.date.isDate(ica_srchCloseYm.getValue()+"01");
    if(!ret) {
        await $c.win.alert("올바른 마감년월을(를) 입력하십시오.");
        ica_srchCloseYm.focus();
        return;
    }
    if (ed_srchAcctDeptCd.getValue() != ed_srchAcctDeptCd.hidVal) {
        // MSG_CM_ERR_038   =  "유효한 @가 아닙니다."
        // $c.win.alert(MSG_CM_ERR_038, ["부서"]);
        await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["부서"]);
        ed_srchAcctDeptCd.focus();
        return;
    }
    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_master.setNoResultMessageVisible(true);
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);
    if (rowCnt > 0) {
        for(let i=0; i<rowCnt; i++) {
            let upperAsetCostCd   = ds_master.getCellData(i, "upperAsetCostCd");
            let upperAsetCostCdNm = ds_master.getCellData(i, "upperAsetCostCdNm");            
            //자산그룹
            ds_master.setCellData(i, "asetGroup",  upperAsetCostCd+" "+upperAsetCostCdNm);
            //계정코드
            let asetCostCd   = ds_master.getCellData(i, "asetCostCd");
            let asetCostCdNm = ds_master.getCellData(i, "asetCostCdNm");            
            ds_master.setCellData(i, "asetCost",  asetCostCd+" "+asetCostCdNm);
        }
        ds_master.reform();
        gr_master.setFocusedCell(0, 2, true);
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg)
};

/**
 * 저장버튼
 */
scwin.f_Save = async function() {
    //변경한 데이터가 있는지 체크한다.
    // if (ds_master.IsUpdated == false) {
    if (ds_master.getModifiedIndex().length < 1) {
        // MSG_CM_ERR_001   = "@은(는) 변경된 사항이 없습니다."
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001) ) {
	    sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        ds_master.reform();
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        $c.sbm.execute(sbm_retrieve);
    }
};

scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * 팝업
 * TOBE 사용안함
 */
scwin.f_PopUp = function (paramArray) {
    var code = ($c.gus.cfIsNull(paramArray.pCode) ? "" : paramArray.pCode);
    var name = ($c.gus.cfIsNull(paramArray.pName) ? "" : paramArray.pName);

    var rtnList = cfCommonPopUp(paramArray.pSelectID, code, name
        , scwin.f_EventCheck(), paramArray.pDispCnt
        , paramArray.pTitle, paramArray.pWidth
        , paramArray.pHidden, paramArray.pWhere
        , paramArray.pW, paramArray.pH
        , paramArray.pTop, paramArray.pLeft
        , paramArray.pExistTF, paramArray.pAllSearchTF
        , paramArray.pWtitleSearch)
    return rtnList;
};

/**
 * 팝업여부검사
 * TOBE 사용안함
 */
scwin.f_IsPopUp = function (inObj) {
    var inValue = $c.gus.cfGetValue(inObj);
    var hidValue = inObj.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.hidVal = "";
        for (var i = 1; i < f_IsPopUp.arguments.length; i++) {
            $c.gus.cfSetValue(f_IsPopUp.arguments[i], "");
        }
        return false;
    }
    if (inValue == hidValue) return false;

    return true;
};


/**
 * 팝업 이벤트에 따라 팝업창의 자동닫기 여부를 반환
 * TOBE : 사용안함
 */
scwin.f_EventCheck = function() {   
    //if (window.event != null && window.event.srcElement.tagName.toUpperCase() == "IMG") {
    if (window.event != null && window.event.srcElement.tagName.toUpperCase() == "btn_") {
        return 'F';
    } else {
        return 'T';
    }
};


