    //         scwin.f_initObj();

    //     ed_coCd.setValue = rtnList[0]; // 코드
    //     ed_coNm.value = rtnList[5]; // 회사명
    //     ed_coCd.hidVal = rtnList[0]; // 히든값
    //     scwin.txtCoClsCd = rtnList[1]; // 회사구분

    // } else {
    //     ed_coCd.setValue = "";
    //     ed_coNm.value = "";
    //     ed_coCd.hidVal = "";
    //     scwin.txtCoClsCd = "";
    // }

    // if (scwin.txtCoClsCd > 'scwin.ACConstants.CO_CLS_CD_DONGBU') { // 자회사 회계 시스템
    //     scwin.isSubCompany = true;
    // } else {
    //     scwin.isSubCompany = false;
    // }

    udc_comCode.cfCommonPopUp(scwin.udc_comCode_callBackFunc, ed_coCd.getValue(), ed_coNm.getValue(), pWinCloseTF, null
                            , null, null, null, null, null
                            , null, null, null, null, null
                            , null, null
